import { RulePattern } from '../types';
import { EmailMessage } from '../types/email-message';
import { extractEmailBodyText } from './email-utils';

const NORMALIZED_FIELD_CACHE = new WeakMap<EmailMessage, Record<string, string>>();

const SUPPORTED_FIELDS: RulePattern['field'][] = ['subject', 'body', 'from.address', 'from.name', 'to', 'headers'];

export interface RuleMatchResult {
  matched: boolean;
  matchedValue: string;
}

export function matchRulePattern(email: EmailMessage, rule: RulePattern): RuleMatchResult {
  if (!SUPPORTED_FIELDS.includes(rule.field)) {
    return { matched: false, matchedValue: '' };
  }

  const normalizedEmail = getNormalizedFields(email);
  const fieldValue = normalizedEmail[rule.field] || '';

  if (rule.operation === 'exists') {
    return {
      matched: fieldValue.length > 0,
      matchedValue: fieldValue.substring(0, 50),
    };
  }

  const values = Array.isArray(rule.values) ? rule.values : rule.values ? [rule.values] : [];

  if (values.length === 0) {
    return { matched: false, matchedValue: '' };
  }

  switch (rule.operation) {
    case 'containsAny': {
      for (const raw of values) {
        const value = raw.toLowerCase();
        if (fieldValue.includes(value)) {
          return { matched: true, matchedValue: raw };
        }
      }
      return { matched: false, matchedValue: '' };
    }

    case 'startsWith': {
      for (const raw of values) {
        const value = raw.toLowerCase();
        if (fieldValue.startsWith(value)) {
          return { matched: true, matchedValue: raw };
        }
      }
      return { matched: false, matchedValue: '' };
    }

    case 'endsWith': {
      for (const raw of values) {
        const value = raw.toLowerCase();
        if (fieldValue.endsWith(value)) {
          return { matched: true, matchedValue: raw };
        }
      }
      return { matched: false, matchedValue: '' };
    }

    case 'regexAny': {
      for (const pattern of values) {
        try {
          const regex = new RegExp(pattern, 'i');
          const match = regex.exec(fieldValue);
          if (match) {
            return { matched: true, matchedValue: match[0] };
          }
        } catch (error) {
          console.warn(`Invalid regex pattern "${pattern}" in rule`, error);
        }
      }
      return { matched: false, matchedValue: '' };
    }

    case 'notContains': {
      for (const raw of values) {
        const value = raw.toLowerCase();
        if (fieldValue.includes(value)) {
          return { matched: false, matchedValue: '' };
        }
      }
      return { matched: false, matchedValue: '' };
    }

    default:
      return { matched: false, matchedValue: '' };
  }
}

function getNormalizedFields(email: EmailMessage): Record<string, string> {
  if (NORMALIZED_FIELD_CACHE.has(email)) {
    return NORMALIZED_FIELD_CACHE.get(email)!;
  }

  const normalized: Record<string, string> = {
    subject: (email.subject || '').toLowerCase(),
    body: (extractEmailBodyText(email) || '').toLowerCase(),
    'from.address': (email.from?.email || '').toLowerCase(),
    'from.name': (email.from?.name || '').toLowerCase(),
    to: formatAddresses(email.to),
    headers: formatHeaders(email),
  };

  NORMALIZED_FIELD_CACHE.set(email, normalized);
  return normalized;
}

function formatAddresses(addresses?: EmailMessage['to']): string {
  if (!addresses || addresses.length === 0) {
    return '';
  }

  return addresses.map((address) => `${address.email} ${address.name ?? ''}`.trim().toLowerCase()).join(' ');
}

function formatHeaders(email: EmailMessage): string {
  if (!email.payload?.headers) {
    return '';
  }

  return email.payload.headers.map((header) => `${header.name}: ${header.value}`.toLowerCase()).join('\n');
}

