    gmailLabels: ['INBOX'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'From', value: 'sender@example.com' },
        { name: 'To', value: 'recipient@example.com' },
        { name: 'Subject', value: 'Test Subject' },
        { name: 'Date', value: 'Wed, 15 Jan 2025 10:00:00 +0000' },
      ],
      body: {
        data: Buffer.from('Test body content').toString('base64url'),
      },
    },
    isProcessed: false,
    processingPriority: 1,
    ...overrides,
  });

  describe('notContains operation', () => {
    it('should return matched: true when pattern is absent (T062 fix)', () => {
      const email = createTestEmail({ subject: 'Important notification' });
