    it('should handle missing domain-sources.json gracefully', () => {
      // Pipeline initialization should not throw even if domain-sources.json is missing
      // (loadDomainLookup returns empty lookup with warning)
      expect(() => new ClassificationPipeline(minimalConfig)).not.toThrow();
    });
  });

  describe('Exclusion Rules Integration (T062)', () => {
    it('should correctly apply notContains rules to filter out unwanted emails', async () => {
      // Create config with notContains exclusion rules
      const configWithExclusions: CategoryConfiguration = {
        ...minimalConfig,
        processingConfig: {
          ...minimalConfig.processingConfig,
          topLevelCategories: {
            ...minimalConfig.processingConfig.topLevelCategories,
            subscriptionContent: {
              description: 'Subscription newsletters and digests',
              subtypes: {
                newsletter: {
                  description: 'Regular newsletters',
                  ruleBasedClassification: {
                    highConfidence: [
                      {
                        field: 'subject',
                        operation: 'containsAny',
                        values: ['newsletter', 'digest', 'weekly update'],
                        weight: 0.7,
                      },
                      {
                        field: 'subject',
                        operation: 'notContains',
                        values: ['unsubscribe', 'spam', 'advertisement'],
                        weight: 0.3,
                      },
                    ],
                  },
                },
              },
              aiFinalClassification: {
                categoryDescription: 'Subscription content and newsletters',
                decisionCriteria: ['Newsletter-like content without spam indicators'],
              },
            },
          },
          categorySignals: {
            ...minimalConfig.processingConfig.categorySignals,
            subscriptionContent: {
              hardAssertions: {},
              strongIndicators: {
                subjectContains: ['newsletter', 'digest'],
              },
            },
          },
        },
      };

      const pipeline = new ClassificationPipeline(configWithExclusions);

      // Test 1: Legitimate newsletter (no exclusion keywords) - should classify as subscriptionContent
      const legitimateNewsletter: EmailMessage = {
        ...mockEmail,
        id: 'newsletter-001',
        subject: 'Weekly Newsletter: Tech Updates',
        from: { email: 'info@techblog.com', name: 'Tech Blog', raw: 'Tech Blog <info@techblog.com>' },
        bodyPlain: 'Here are this week\'s top stories...',
      };

      const result1 = await pipeline.classify(legitimateNewsletter);
      expect(result1.primaryCategory).toBe('subscriptionContent');

      // Test 2: Newsletter with "unsubscribe" keyword - should have lower score or different category
      const spamNewsletter: EmailMessage = {
        ...mockEmail,
        id: 'newsletter-002',
        subject: 'Weekly Newsletter: Click here to unsubscribe',
        from: { email: 'spam@spammer.com', name: 'Spammer', raw: 'Spammer <spam@spammer.com>' },
        bodyPlain: 'Buy now! Limited time offer!',
      };

      const result2 = await pipeline.classify(spamNewsletter);
      // notContains rule should fail, reducing the score for subscriptionContent
      // Either different category or lower confidence
      if (result2.primaryCategory === 'subscriptionContent') {
        expect(result2.confidence).toBeLessThan(result1.confidence);
      } else {
        expect(result2.primaryCategory).not.toBe('subscriptionContent');
      }

      // Test 3: Newsletter with "advertisement" keyword - should be filtered out
      const advertisementEmail: EmailMessage = {
        ...mockEmail,
        id: 'newsletter-003',
        subject: 'Weekly Newsletter - Special Advertisement',
        from: { email: 'ads@advertiser.com', name: 'Advertiser', raw: 'Advertiser <ads@advertiser.com>' },
        bodyPlain: 'Check out our sponsors...',
      };

      const result3 = await pipeline.classify(advertisementEmail);
      // notContains rule should fail
      if (result3.primaryCategory === 'subscriptionContent') {
        expect(result3.confidence).toBeLessThan(result1.confidence);
      } else {
        expect(result3.primaryCategory).not.toBe('subscriptionContent');
      }
    });

    it('should apply notContains to body field for spam detection', async () => {
      const configWithBodyExclusions: CategoryConfiguration = {
        ...minimalConfig,
        processingConfig: {
          ...minimalConfig.processingConfig,
          topLevelCategories: {
            ...minimalConfig.processingConfig.topLevelCategories,
            professional: {
              description: 'Professional communications',
              subtypes: {
                correspondence: {
                  description: 'Professional email correspondence',
                  ruleBasedClassification: {
                    highConfidence: [
                      {
                        field: 'subject',
                        operation: 'containsAny',
                        values: ['meeting', 'project', 'review'],
                        weight: 0.5,
                      },
                      {
                        field: 'body',
                        operation: 'notContains',
                        values: ['click here', 'buy now', 'limited time offer'],
                        weight: 0.5,
                      },
                    ],
                  },
                },
              },
              aiFinalClassification: {
                categoryDescription: 'Professional work-related communications',
                decisionCriteria: ['Professional tone without spam indicators'],
              },
            },
          },
          categorySignals: {
            ...minimalConfig.processingConfig.categorySignals,
            professional: {
              hardAssertions: {},
              strongIndicators: {
                subjectContains: ['meeting', 'project'],
              },
            },
          },
        },
      };

      const pipeline = new ClassificationPipeline(configWithBodyExclusions);

      // Test 1: Professional email without spam keywords
      const professionalEmail: EmailMessage = {
        ...mockEmail,
        id: 'prof-001',
        subject: 'Project Review Meeting',
        from: { email: 'colleague@company.com', name: 'Colleague', raw: 'Colleague <colleague@company.com>' },
        bodyPlain: 'Hi, let\'s schedule a meeting to review the project progress.',
        payload: {
          ...mockEmail.payload,
          body: {
            data: Buffer.from('Hi, let\'s schedule a meeting to review the project progress.').toString('base64url'),
          },
        },
      };

      const result1 = await pipeline.classify(professionalEmail);
      expect(result1.primaryCategory).toBe('professional');

      // Test 2: Email with spam keywords in body should be filtered
      const spamEmail: EmailMessage = {
        ...mockEmail,
        id: 'prof-002',
        subject: 'Project Update',
        from: { email: 'spammer@spam.com', name: 'Spammer', raw: 'Spammer <spammer@spam.com>' },
        bodyPlain: 'Click here to buy now! Limited time offer on our project management tools.',
        payload: {
          ...mockEmail.payload,
          body: {
            data: Buffer.from('Click here to buy now! Limited time offer on our project management tools.').toString('base64url'),
          },
        },
      };

      const result2 = await pipeline.classify(spamEmail);
      // notContains rule should fail due to spam keywords in body
      if (result2.primaryCategory === 'professional') {
        expect(result2.confidence).toBeLessThan(result1.confidence);
      } else {
        expect(result2.primaryCategory).not.toBe('professional');
      }
    });
  });
});

