/**
 * Email Utilities
 *
 * Business-logic-agnostic utility functions for email processing.
 * These functions are reused across multiple classification stages.
 */

/**
 * Extract domain from email address
 * @param email Email address (e.g., "user@example.com")
 * @returns Domain portion (e.g., "example.com") in lowercase
 */
export function extractDomainFromEmail(email: string): string {
  const atIndex = email.lastIndexOf('@');
  if (atIndex === -1) {
    return email; // Invalid email, return as-is
  }
  return email.substring(atIndex + 1).toLowerCase();
}

/**
 * Check if email domain matches configured domain
 * Supports exact matches and subdomain matching
 *
 * @param emailDomain Domain from email address (should be lowercase)
 * @param configDomain Domain from configuration
 * @returns True if domains match
 *
 * @example
 * domainMatches("chase.com", "chase.com") // true - exact match
 * domainMatches("noreply.chase.com", "chase.com") // true - subdomain match
 * domainMatches("chase.net", "chase.com") // false - different domain
 */
export function domainMatches(emailDomain: string, configDomain: string): boolean {
  const emailDomainLower = emailDomain.toLowerCase();
  const configDomainLower = configDomain.toLowerCase();

  // Exact match
  if (emailDomainLower === configDomainLower) {
    return true;
  }

  // Subdomain match (e.g., noreply.chase.com matches chase.com)
  if (emailDomainLower.endsWith('.' + configDomainLower)) {
    return true;
  }

  return false;
}

/**
 * Extract plain text from HTML content
 * Removes HTML tags, scripts, styles, and normalizes whitespace.
 * For production use, consider using a proper HTML parser like jsdom or cheerio.
 *
 * @param html HTML content
 * @returns Plain text content with normalized whitespace
 *
 * @example
 * extractTextFromHtml("<p>Hello <b>world</b>!</p>") // "Hello world!"
 * extractTextFromHtml("<div>Line 1<br>Line 2</div>") // "Line 1 Line 2"
 */
export function extractTextFromHtml(html: string): string {
  return html
    .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, ' ') // Remove script tags and content (add space)
    .replace(/<style\b[^<]*(?:(?!<\/style>)<[^<]*)*<\/style>/gi, ' ') // Remove style tags and content (add space)
    .replace(/<[^>]*>/g, ' ') // Remove all HTML tags (add space)
    .replace(/&nbsp;/g, ' ') // Replace non-breaking spaces with regular spaces
    .replace(/&lt;/g, '<') // Replace common HTML entities
    .replace(/&gt;/g, '>')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&[^;]+;/g, '') // Remove any remaining HTML entities
    .replace(/\s+/g, ' ') // Normalize all whitespace to single spaces
    .trim();
}

/**
 * Extract body text from email message
 * Prefers plain text body, falls back to extracting text from HTML body.
 * This function standardizes body text extraction across all classification stages.
 *
 * @param email Email message object with bodyPlain and/or bodyHtml fields
 * @returns Extracted body text (plain or from HTML), empty string if no body content
 *
 * @example
 * // With plain text
