import { matchRulePattern } from '../../../src/utils/rule-matcher';
import { EmailMessage } from '../../../src/types/email-message';
import { RulePattern } from '../../../src/types';

describe('matchRulePattern', () => {
  const createTestEmail = (overrides?: Partial<EmailMessage>): EmailMessage => ({
    id: 'test-123',
    threadId: 'thread-123',
    from: { email: 'sender@example.com', name: 'Test Sender', raw: 'Test Sender <sender@example.com>' },
    to: [{ email: 'recipient@example.com', name: 'Test Recipient', raw: 'Test Recipient <recipient@example.com>' }],
    subject: 'Test Subject',
    date: new Date('2025-01-15T10:00:00Z'),
    gmailLabels: ['INBOX'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'From', value: 'sender@example.com' },
        { name: 'To', value: 'recipient@example.com' },
        { name: 'Subject', value: 'Test Subject' },
        { name: 'Date', value: 'Wed, 15 Jan 2025 10:00:00 +0000' },
      ],
      body: {
        data: Buffer.from('Test body content').toString('base64url'),
      },
    },
    isProcessed: false,
    processingPriority: 1,
    ...overrides,
  });

  describe('notContains operation', () => {
    it('should return matched: true when pattern is absent (T062 fix)', () => {
      const email = createTestEmail({ subject: 'Important notification' });
      const rule: RulePattern = {
        field: 'subject',
        operation: 'notContains',
        values: ['unsubscribe', 'spam', 'advertisement'],
        weight: 1,
      };

      const result = matchRulePattern(email, rule);

      expect(result.matched).toBe(true);
      expect(result.matchedValue).toBe('');
    });

    it('should return matched: false when pattern is present', () => {
      const email = createTestEmail({ subject: 'Click here to unsubscribe' });
      const rule: RulePattern = {
        field: 'subject',
        operation: 'notContains',
        values: ['unsubscribe', 'spam', 'advertisement'],
        weight: 1,
      };

      const result = matchRulePattern(email, rule);

      expect(result.matched).toBe(false);
      expect(result.matchedValue).toBe('');
    });

    it('should be case-insensitive', () => {
      const email = createTestEmail({ subject: 'Get your free ADVERTISEMENT now' });
      const rule: RulePattern = {
        field: 'subject',
        operation: 'notContains',
        values: ['advertisement'],
        weight: 1,
      };

      const result = matchRulePattern(email, rule);

      expect(result.matched).toBe(false);
      expect(result.matchedValue).toBe('');
    });

    it('should check all values and return false if any match', () => {
      const email = createTestEmail({ subject: 'Limited time offer - act now!' });
      const rule: RulePattern = {
        field: 'subject',
        operation: 'notContains',
        values: ['unsubscribe', 'spam', 'offer', 'advertisement'],
        weight: 1,
      };

      const result = matchRulePattern(email, rule);

      expect(result.matched).toBe(false);
      expect(result.matchedValue).toBe('');
    });

    it('should work with body field for exclusion rules', () => {
      const email = createTestEmail({
        payload: {
          mimeType: 'text/plain',
          headers: [],
          body: {
            data: Buffer.from('This is a legitimate newsletter with useful content').toString('base64url'),
          },
        },
      });

      const rule: RulePattern = {
        field: 'body',
        operation: 'notContains',
        values: ['click here', 'buy now', 'limited time'],
        weight: 1,
      };

      const result = matchRulePattern(email, rule);

      expect(result.matched).toBe(true);
      expect(result.matchedValue).toBe('');
    });

    it('should return false when body contains excluded pattern', () => {
      const email = createTestEmail({
        payload: {
          mimeType: 'text/plain',
          headers: [],
          body: {
            data: Buffer.from('Click here to claim your prize!').toString('base64url'),
          },
        },
      });

      const rule: RulePattern = {
        field: 'body',
        operation: 'notContains',
        values: ['click here', 'buy now', 'limited time'],
        weight: 1,
      };

      const result = matchRulePattern(email, rule);

      expect(result.matched).toBe(false);
      expect(result.matchedValue).toBe('');
    });
  });

  describe('other operations (sanity check)', () => {
    it('should handle containsAny operation', () => {
      const email = createTestEmail({ subject: 'Receipt #12345' });
      const rule: RulePattern = {
        field: 'subject',
        operation: 'containsAny',
        values: ['receipt', 'invoice'],
        weight: 1,
      };

      const result = matchRulePattern(email, rule);

      expect(result.matched).toBe(true);
      expect(result.matchedValue).toBe('receipt');
    });

    it('should handle startsWith operation', () => {
      const email = createTestEmail({ subject: 'Payment confirmation for order' });
      const rule: RulePattern = {
        field: 'subject',
        operation: 'startsWith',
        values: ['payment'],
        weight: 1,
      };

      const result = matchRulePattern(email, rule);

      expect(result.matched).toBe(true);
      expect(result.matchedValue).toBe('payment');
    });

    it('should handle exists operation', () => {
      const email = createTestEmail({ subject: 'Test' });
      const rule: RulePattern = {
        field: 'subject',
        operation: 'exists',
        weight: 1,
      };

      const result = matchRulePattern(email, rule);

      expect(result.matched).toBe(true);
    });
  });
});

